const key = ([x, y]: Cell): string => `${x},${y}`;

const neighborsOf = ([x, y]: Cell): Cell[] =>
  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);

const isAliveNextGen = (wasAlive: boolean, liveNeighbors: number): boolean =>
  liveNeighbors === 3 || (wasAlive && liveNeighbors === 2);

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const alive = new Set(liveCells.map(key));
  const liveNeighborCounts = new Map<string, { cell: Cell; count: number }>();

  for (const cell of liveCells) {
    for (const neighbor of neighborsOf(cell)) {
      const k = key(neighbor);
      const entry = liveNeighborCounts.get(k) ?? { cell: neighbor, count: 0 };
      entry.count++;
      liveNeighborCounts.set(k, entry);
    }
  }

  const survivors = liveCells.filter((cell) => {
    const entry = liveNeighborCounts.get(key(cell));
    return isAliveNextGen(true, entry?.count ?? 0);
  });
  const births = [...liveNeighborCounts.values()]
    .filter(({ cell, count }) => !alive.has(key(cell)) && isAliveNextGen(false, count))
    .map(({ cell }) => cell);

  return [...survivors, ...births];
}

